import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { login } from '../store/slices/authSlice';
import api from '../services/api';

export default function Login() {
  const dispatch = useDispatch();
  const { loading, error } = useSelector(s => s.auth);
  const [email,    setEmail]    = useState('admin');
  const [password, setPassword] = useState('admin123');
  const [school,   setSchool]   = useState({ name:'EduErpee', primaryColor:'#1a7a6e' });
  const [showPass, setShowPass] = useState(false);

  useEffect(() => {
    api.get('/schools/settings').then(r => {
      const d = r.data.data;
      if (d?.schoolName)    setSchool(s=>({...s, name: d.schoolName}));
      if (d?.primaryColor)  setSchool(s=>({...s, primaryColor: d.primaryColor}));
    }).catch(()=>{});
  }, []);

  const handleSubmit = (e) => {
    e.preventDefault();
    dispatch(login({ username: email, password }));
  };

  const C = school.primaryColor || '#1a7a6e';

  return (
    <div style={{display:'flex',height:'100vh',fontFamily:"'Segoe UI',Arial,sans-serif",overflow:'hidden'}}>

      {/* LEFT — Illustration Panel */}
      <div style={{flex:1,background:C,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',padding:'40px',position:'relative',overflow:'hidden'}}>

        {/* Background circles */}
        <div style={{position:'absolute',top:-80,left:-80,width:300,height:300,borderRadius:'50%',background:'rgba(255,255,255,.06)'}}/>
        <div style={{position:'absolute',bottom:-60,right:-60,width:240,height:240,borderRadius:'50%',background:'rgba(255,255,255,.06)'}}/>
        <div style={{position:'absolute',top:'30%',right:-40,width:160,height:160,borderRadius:'50%',background:'rgba(255,255,255,.04)'}}/>

        {/* Logo */}
        <div style={{position:'absolute',top:32,left:36,display:'flex',alignItems:'center',gap:10}}>
          <div style={{width:38,height:38,borderRadius:10,background:'rgba(255,255,255,.2)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:20}}>🎓</div>
          <div>
            <div style={{fontWeight:800,fontSize:16,color:'#fff',letterSpacing:'.02em'}}>{school.name}</div>
            <div style={{fontSize:10,color:'rgba(255,255,255,.7)',letterSpacing:'.08em',textTransform:'uppercase'}}>School ERP</div>
          </div>
        </div>

        {/* Illustration SVG */}
        <svg viewBox="0 0 500 420" style={{width:'100%',maxWidth:480,marginTop:40,zIndex:1}} xmlns="http://www.w3.org/2000/svg">
          {/* Ground */}
          <ellipse cx="250" cy="400" rx="200" ry="18" fill="rgba(0,0,0,.1)"/>

          {/* Signboard post */}
          <rect x="246" y="220" width="8" height="120" rx="4" fill="rgba(255,255,255,.4)"/>
          {/* Signboard */}
          <rect x="200" y="170" width="100" height="60" rx="10" fill="rgba(255,255,255,.9)"/>
          <text x="250" y="196" textAnchor="middle" fontSize="11" fontWeight="700" fill={C}>SCHOOL</text>
          <text x="250" y="214" textAnchor="middle" fontSize="11" fontWeight="700" fill={C}>ZONE</text>
          {/* Signboard figure icons */}
          <text x="250" y="230" textAnchor="middle" fontSize="16">🚸</text>

          {/* Mother */}
          {/* Body */}
          <ellipse cx="160" cy="240" rx="22" ry="50" fill="#E8A87C"/>
          <rect x="140" y="235" width="40" height="80" rx="10" fill="#E53935"/>
          {/* Head */}
          <circle cx="160" cy="195" r="26" fill="#FFCC99"/>
          {/* Hair */}
          <path d="M134 192 Q140 165 160 162 Q180 165 186 192 Q180 178 160 176 Q140 178 134 192Z" fill="#3E2723"/>
          {/* Eyes */}
          <circle cx="152" cy="192" r="3" fill="#3E2723"/>
          <circle cx="168" cy="192" r="3" fill="#3E2723"/>
          {/* Smile */}
          <path d="M153 202 Q160 208 167 202" stroke="#C0392B" strokeWidth="1.5" fill="none" strokeLinecap="round"/>
          {/* Arm holding bag */}
          <line x1="140" y1="255" x2="118" y2="290" stroke="#E53935" strokeWidth="10" strokeLinecap="round"/>
          {/* Bag */}
          <rect x="100" y="285" width="30" height="25" rx="5" fill="#1565C0"/>
          <rect x="108" y="280" width="14" height="8" rx="3" fill="#1565C0"/>
          {/* Other arm - holding child's hand */}
          <line x1="180" y1="255" x2="205" y2="280" stroke="#E53935" strokeWidth="10" strokeLinecap="round"/>
          {/* Legs */}
          <rect x="146" y="308" width="14" height="60" rx="7" fill="#E53935"/>
          <rect x="162" y="308" width="14" height="55" rx="7" fill="#E53935"/>
          {/* Shoes */}
          <ellipse cx="153" cy="370" rx="12" ry="6" fill="#3E2723"/>
          <ellipse cx="169" cy="366" rx="12" ry="6" fill="#3E2723"/>

          {/* Child 1 (bigger) */}
          {/* Body */}
          <rect x="196" y="288" width="28" height="55" rx="8" fill="#1565C0"/>
          {/* Head */}
          <circle cx="210" cy="272" r="18" fill="#FFCC99"/>
          {/* Hair */}
          <path d="M192 268 Q198 252 210 250 Q222 252 228 268 Q222 258 210 256 Q198 258 192 268Z" fill="#3E2723"/>
          {/* Face */}
          <circle cx="205" cy="270" r="2.5" fill="#3E2723"/>
          <circle cx="215" cy="270" r="2.5" fill="#3E2723"/>
          <path d="M205 279 Q210 284 215 279" stroke="#C0392B" strokeWidth="1.5" fill="none" strokeLinecap="round"/>
          {/* Arm holding schoolbag */}
          <line x1="196" y1="305" x2="180" y2="328" stroke="#1565C0" strokeWidth="8" strokeLinecap="round"/>
          {/* Schoolbag */}
          <rect x="162" y="322" width="24" height="30" rx="5" fill="#F57F17"/>
          <rect x="168" y="317" width="12" height="8" rx="3" fill="#F57F17"/>
          <circle cx="174" cy="337" r="3" fill="rgba(0,0,0,.2)"/>
          {/* Other arm - held by mother */}
          <line x1="224" y1="305" x2="205" y2="282" stroke="#1565C0" strokeWidth="8" strokeLinecap="round"/>
          {/* Legs */}
          <rect x="200" y="338" width="11" height="40" rx="6" fill="#1565C0"/>
          <rect x="214" y="338" width="11" height="36" rx="6" fill="#1565C0"/>
          <ellipse cx="205" cy="379" rx="10" ry="5" fill="#3E2723"/>
          <ellipse cx="219" cy="375" rx="10" ry="5" fill="#3E2723"/>

          {/* Child 2 (smaller, front) */}
          {/* Body */}
          <rect x="292" y="305" width="24" height="48" rx="7" fill="#E91E63"/>
          {/* Head */}
          <circle cx="304" cy="290" r="16" fill="#FFCC99"/>
          {/* Pigtails */}
          <circle cx="290" cy="283" r="6" fill="#3E2723"/>
          <circle cx="318" cy="283" r="6" fill="#3E2723"/>
          <path d="M288 282 Q296 272 304 270 Q312 272 320 282 Q314 275 304 274 Q294 275 288 282Z" fill="#3E2723"/>
          {/* Face */}
          <circle cx="299" cy="289" r="2" fill="#3E2723"/>
          <circle cx="309" cy="289" r="2" fill="#3E2723"/>
          <path d="M299 297 Q304 301 309 297" stroke="#C0392B" strokeWidth="1.5" fill="none" strokeLinecap="round"/>
          {/* Arm - held by child 1 */}
          <line x1="292" y1="318" x2="276" y2="310" stroke="#E91E63" strokeWidth="7" strokeLinecap="round"/>
          {/* Arm - free */}
          <line x1="316" y1="318" x2="330" y2="335" stroke="#E91E63" strokeWidth="7" strokeLinecap="round"/>
          {/* Small bag */}
          <rect x="326" y="330" width="18" height="22" rx="4" fill="#7B1FA2"/>
          {/* Legs */}
          <rect x="295" y="349" width="9" height="32" rx="5" fill="#E91E63"/>
          <rect x="308" y="349" width="9" height="29" rx="5" fill="#E91E63"/>
          <ellipse cx="299" cy="382" rx="9" ry="4" fill="#3E2723"/>
          <ellipse cx="312" cy="379" rx="9" ry="4" fill="#3E2723"/>

          {/* Decorative elements */}
          <circle cx="80" cy="180" r="12" fill="rgba(255,255,255,.15)"/>
          <circle cx="420" cy="160" r="8" fill="rgba(255,255,255,.15)"/>
          <circle cx="390" cy="340" r="10" fill="rgba(255,255,255,.1)"/>
          <circle cx="70" cy="330" r="6" fill="rgba(255,255,255,.1)"/>
        </svg>

        {/* Bottom tagline */}
        <div style={{zIndex:1,textAlign:'center',marginTop:8}}>
          <div style={{fontSize:22,fontWeight:800,color:'#fff',letterSpacing:'.01em'}}>Manage Smarter,</div>
          <div style={{fontSize:22,fontWeight:800,color:'rgba(255,255,255,.75)'}}>Teach Better.</div>
          <div style={{fontSize:12,color:'rgba(255,255,255,.6)',marginTop:6}}>Complete School Management Solution</div>
        </div>
      </div>

      {/* RIGHT — Login Form */}
      <div style={{width:420,background:'#fff',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',padding:'48px 48px',boxShadow:'-4px 0 32px rgba(0,0,0,.08)'}}>

        <div style={{width:'100%',maxWidth:340}}>
          {/* Welcome text */}
          <div style={{marginBottom:36}}>
            <h1 style={{fontSize:28,fontWeight:800,color:'#1a1a2e',marginBottom:6,letterSpacing:'-.01em'}}>Welcome</h1>
            <p style={{fontSize:13,color:'#9CA3AF',fontWeight:400}}>Sign in to your admin account</p>
          </div>

          {/* Error */}
          {error && (
            <div style={{padding:'10px 14px',background:'#FEF2F2',border:'1px solid #FECACA',borderRadius:10,color:'#DC2626',fontSize:12,marginBottom:20,display:'flex',alignItems:'center',gap:8}}>
              ❌ {typeof error==='string'?error:'Invalid credentials'}
            </div>
          )}

          <form onSubmit={handleSubmit}>
            {/* Email */}
            <div style={{marginBottom:18}}>
              <label style={{display:'block',fontSize:12,fontWeight:600,color:'#374151',marginBottom:7}}>
                Email <span style={{color:'#EF4444'}}>*</span>
              </label>
              <div style={{position:'relative'}}>
                <span style={{position:'absolute',left:12,top:'50%',transform:'translateY(-50%)',fontSize:14,color:'#9CA3AF'}}>✉️</span>
                <input
                  required value={email} onChange={e=>setEmail(e.target.value)}
                  placeholder="Enter your email"
                  style={{width:'100%',padding:'11px 12px 11px 36px',border:'1.5px solid #E5E7EB',borderRadius:10,fontSize:13,outline:'none',boxSizing:'border-box',transition:'border .2s',fontFamily:'inherit',background:'#FAFAFA'}}
                  onFocus={e=>e.target.style.borderColor=C}
                  onBlur={e=>e.target.style.borderColor='#E5E7EB'}
                />
              </div>
            </div>

            {/* Password */}
            <div style={{marginBottom:10}}>
              <label style={{display:'block',fontSize:12,fontWeight:600,color:'#374151',marginBottom:7}}>
                Password <span style={{color:'#EF4444'}}>*</span>
              </label>
              <div style={{position:'relative'}}>
                <span style={{position:'absolute',left:12,top:'50%',transform:'translateY(-50%)',fontSize:14,color:'#9CA3AF'}}>🔒</span>
                <input
                  required type={showPass?'text':'password'}
                  value={password} onChange={e=>setPassword(e.target.value)}
                  placeholder="Enter your password"
                  style={{width:'100%',padding:'11px 40px 11px 36px',border:'1.5px solid #E5E7EB',borderRadius:10,fontSize:13,outline:'none',boxSizing:'border-box',transition:'border .2s',fontFamily:'inherit',background:'#FAFAFA'}}
                  onFocus={e=>e.target.style.borderColor=C}
                  onBlur={e=>e.target.style.borderColor='#E5E7EB'}
                />
                <button type="button" onClick={()=>setShowPass(!showPass)}
                  style={{position:'absolute',right:12,top:'50%',transform:'translateY(-50%)',background:'none',border:'none',cursor:'pointer',fontSize:14,color:'#9CA3AF',padding:0}}>
                  {showPass?'🙈':'👁️'}
                </button>
              </div>
            </div>

            {/* Forgot password */}
            <div style={{textAlign:'right',marginBottom:28}}>
              <span style={{fontSize:12,color:C,cursor:'pointer',fontWeight:600}}>Forgot your password?</span>
            </div>

            {/* Submit */}
            <button type="submit" disabled={loading}
              style={{width:'100%',padding:'13px',background:loading?'#9CA3AF':C,color:'#fff',border:'none',borderRadius:10,fontSize:14,fontWeight:700,cursor:loading?'not-allowed':'pointer',transition:'all .2s',letterSpacing:'.02em',boxShadow:`0 4px 16px ${C}55`}}>
              {loading ? '⏳ Signing in…' : 'Log In'}
            </button>
          </form>

          {/* Footer */}
          <div style={{textAlign:'center',marginTop:28,fontSize:12,color:'#9CA3AF'}}>
            Powered by <strong style={{color:C}}>{school.name}</strong> School ERP
          </div>
        </div>
      </div>
    </div>
  );
}
